220 Value *InstCombinerImpl::EmitGEPOffsets(ArrayRef<GEPOperator *> GEPs,
221                                         GEPNoWrapFlags NW, Type *IdxTy,
222                                         bool RewriteGEPs) {
223   Value *Sum = nullptr;
224   for (GEPOperator *GEP : reverse(GEPs)) {
225     Value *Offset = EmitGEPOffset(GEP, RewriteGEPs);
226     if (Offset->getType() != IdxTy)
227       Offset = Builder.CreateVectorSplat(
228           cast<VectorType>(IdxTy)->getElementCount(), Offset);
229     if (Sum)
230       Sum = Builder.CreateAdd(Sum, Offset, "", NW.hasNoUnsignedWrap(),
231                               NW.isInBounds());
232     else
233       Sum = Offset;
234   }
235   if (!Sum)
236     return Constant::getNullValue(IdxTy);
237   return Sum;
238 }
