7462 // This helper will be called with icmp operands in both orders.
7463 Instruction *InstCombinerImpl::foldICmpCommutative(CmpPredicate Pred,
7464                                                    Value *Op0, Value *Op1,
7465                                                    ICmpInst &CxtI) {
7466   // Try to optimize 'icmp GEP, P' or 'icmp P, GEP'.
7467   if (auto *GEP = dyn_cast<GEPOperator>(Op0))
7468     if (Instruction *NI = foldGEPICmp(GEP, Op1, Pred, CxtI))
7469       return NI;
7470 
7471   if (auto *SI = dyn_cast<SelectInst>(Op0))
7472     if (Instruction *NI = foldSelectICmp(Pred, SI, Op1, CxtI))
7473       return NI;
7474 
7475   if (auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op0))
7476     if (Instruction *Res = foldICmpWithMinMax(CxtI, MinMax, Op1, Pred))
7477       return Res;
7478 
7479   {
7480     Value *X;
7481     const APInt *C;
7482     // icmp X+Cst, X
7483     if (match(Op0, m_Add(m_Value(X), m_APInt(C))) && Op1 == X)
7484       return foldICmpAddOpConst(X, *C, Pred);
7485   }
7486 
7487   // abs(X) >=  X --> true
7488   // abs(X) u<= X --> true
7489   // abs(X) <   X --> false
7490   // abs(X) u>  X --> false
7491   // abs(X) u>= X --> IsIntMinPosion ? `X > -1`: `X u<= INTMIN`
7492   // abs(X) <=  X --> IsIntMinPosion ? `X > -1`: `X u<= INTMIN`
7493   // abs(X) ==  X --> IsIntMinPosion ? `X > -1`: `X u<= INTMIN`
7494   // abs(X) u<  X --> IsIntMinPosion ? `X < 0` : `X >   INTMIN`
7495   // abs(X) >   X --> IsIntMinPosion ? `X < 0` : `X >   INTMIN`
7496   // abs(X) !=  X --> IsIntMinPosion ? `X < 0` : `X >   INTMIN`
7497   {
7498     Value *X;
7499     Constant *C;
7500     if (match(Op0, m_Intrinsic<Intrinsic::abs>(m_Value(X), m_Constant(C))) &&
7501         match(Op1, m_Specific(X))) {
7502       Value *NullValue = Constant::getNullValue(X->getType());
7503       Value *AllOnesValue = Constant::getAllOnesValue(X->getType());
7504       const APInt SMin =
7505           APInt::getSignedMinValue(X->getType()->getScalarSizeInBits());
7506       bool IsIntMinPosion = C->isAllOnesValue();
7507       switch (Pred) {
7508       case CmpInst::ICMP_ULE:
7509       case CmpInst::ICMP_SGE:
7510         return replaceInstUsesWith(CxtI, ConstantInt::getTrue(CxtI.getType()));
7511       case CmpInst::ICMP_UGT:
7512       case CmpInst::ICMP_SLT:
7513         return replaceInstUsesWith(CxtI, ConstantInt::getFalse(CxtI.getType()));
7514       case CmpInst::ICMP_UGE:
7515       case CmpInst::ICMP_SLE:
7516       case CmpInst::ICMP_EQ: {
7517         return replaceInstUsesWith(
7518             CxtI, IsIntMinPosion
7519                       ? Builder.CreateICmpSGT(X, AllOnesValue)
7520                       : Builder.CreateICmpULT(
7521                             X, ConstantInt::get(X->getType(), SMin + 1)));
7522       }
7523       case CmpInst::ICMP_ULT:
7524       case CmpInst::ICMP_SGT:
7525       case CmpInst::ICMP_NE: {
7526         return replaceInstUsesWith(
7527             CxtI, IsIntMinPosion
7528                       ? Builder.CreateICmpSLT(X, NullValue)
7529                       : Builder.CreateICmpUGT(
7530                             X, ConstantInt::get(X->getType(), SMin)));
7531       }
7532       default:
7533         llvm_unreachable("Invalid predicate!");
7534       }
7535     }
7536   }
7537 
7538   const SimplifyQuery Q = SQ.getWithInstruction(&CxtI);
7539   if (Value *V = foldICmpWithLowBitMaskedVal(Pred, Op0, Op1, Q, *this))
7540     return replaceInstUsesWith(CxtI, V);
7541 
7542   // Folding (X / Y) pred X => X swap(pred) 0 for constant Y other than 0 or 1
7543   auto CheckUGT1 = [](const APInt &Divisor) { return Divisor.ugt(1); };
7544   {
7545     if (match(Op0, m_UDiv(m_Specific(Op1), m_CheckedInt(CheckUGT1)))) {
7546       return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Op1,
7547                           Constant::getNullValue(Op1->getType()));
7548     }
7549 
7550     if (!ICmpInst::isUnsigned(Pred) &&
7551         match(Op0, m_SDiv(m_Specific(Op1), m_CheckedInt(CheckUGT1)))) {
7552       return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Op1,
7553                           Constant::getNullValue(Op1->getType()));
7554     }
7555   }
7556 
7557   // Another case of this fold is (X >> Y) pred X => X swap(pred) 0 if Y != 0
7558   auto CheckNE0 = [](const APInt &Shift) { return !Shift.isZero(); };
7559   {
7560     if (match(Op0, m_LShr(m_Specific(Op1), m_CheckedInt(CheckNE0)))) {
7561       return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Op1,
7562                           Constant::getNullValue(Op1->getType()));
7563     }
7564 
7565     if ((Pred == CmpInst::ICMP_SLT || Pred == CmpInst::ICMP_SGE) &&
7566         match(Op0, m_AShr(m_Specific(Op1), m_CheckedInt(CheckNE0)))) {
7567       return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Op1,
7568                           Constant::getNullValue(Op1->getType()));
7569     }
7570   }
7571 
7572   return nullptr;
7573 }
